91	func shouldFallbackToV1AfterV2ProbeError(conn Conn, err error) bool {
92		if conn == nil || conn.Endpoint() == nil {
93			return false
94		}
95		switch conn.Endpoint().Scheme {
96		case "ssh", "git+ssh":
97		default:
98			return false
99		}
100	
101		msg := err.Error()
102		return strings.Contains(msg, "Invalid command:") &&
103			strings.Contains(msg, "GIT_PROTOCOL='version=2'") &&
