116	// AdvRefsToSlice converts an AdvRefs to a slice of references.
117	func AdvRefsToSlice(ar *packp.AdvRefs) ([]*plumbing.Reference, error) {
118		refs, err := ar.AllReferences()
119		if err != nil {
120			return nil, fmt.Errorf("all references: %w", err)
121		}
122		iter, err := refs.IterReferences()
123		if err != nil {
124			return nil, fmt.Errorf("iter references: %w", err)
125		}
126		defer iter.Close()
127	
128		var out []*plumbing.Reference
129		err = iter.ForEach(func(ref *plumbing.Reference) error {
130			out = append(out, ref)
131			return nil
132		})
133		if err != nil {
134			return nil, fmt.Errorf("iterate references: %w", err)
135		}
136		return out, nil
137	}
