58	func requestInfoRefsWithCommand(ctx context.Context, service string, cmd *sshCommand, stderr *sshCommandError) ([]byte, error) {
59		if err := cmd.Stdin.Close(); err != nil {
60			return nil, fmt.Errorf("close ssh stdin for %s: %w", service, errors.Join(err, cleanupSSHCommand(cmd)))
61		}
62		data, readErr := io.ReadAll(cmd.Stdout)
63		waitErr := cmd.wait()
64		if ctx.Err() != nil {
65			return nil, errors.Join(ctx.Err(), readErr, stderr.wrap(waitErr))
66		}
67		if readErr != nil {
68			return nil, fmt.Errorf("%s info-refs: %w", service, readErr)
69		}
70		if len(data) > 0 {
71			return data, nil
72		}
73		if waitErr != nil {
