164	func sshRemoteCommand(ep *url.URL, service string, gitProtocol string) (string, error) {
165		if ep == nil || ep.Path == "" {
166			return "", errors.New("missing SSH repository path")
167		}
168		path := shellQuotePath(ep.Path)
169		if gitProtocol != "" {
170			return gitProtocolEnv(gitProtocol) + " " + service + " " + path, nil
171		}
172		return service + " " + path, nil
173	}
174	
175	func gitProtocolEnv(gitProtocol string) string {
176		return "GIT_PROTOCOL=" + shellQuote(gitProtocol)
177	}
178	
179	func shellQuote(s string) string {
180		return "'" + strings.ReplaceAll(s, "'", `'"'"'`) + "'"
181	}
182	
183	func shellQuotePath(path string) string {
184		if !strings.HasPrefix(path, "~") {
185			return shellQuote(path)
186		}
187		slash := strings.IndexByte(path, '/')
188		if slash < 0 {
189			return path
190		}
191		return path[:slash+1] + shellQuote(path[slash+1:])
192	}
