194	type sshCommand struct {
195		Cmd    *exec.Cmd
196		Stdin  io.WriteCloser
197		Stdout io.ReadCloser
198		waitFn func() error
199	}
200	
201	func (c *sshCommand) wait() error {
202		if c.waitFn != nil {
203			return c.waitFn()
204		}
205		if err := c.Cmd.Wait(); err != nil {
206			return fmt.Errorf("wait for ssh command: %w", err)
207		}
208		return nil
209	}
210	
211	func cleanupSSHCommand(cmd *sshCommand) error {
212		if cmd == nil {
213			return nil
214		}
215		var errs []error
216		if cmd.Stdout != nil {
217			if err := cmd.Stdout.Close(); err != nil {
218				errs = append(errs, fmt.Errorf("close ssh stdout: %w", err))
219			}
220		}
221		if err := cmd.wait(); err != nil {
222			errs = append(errs, err)
223		}
224		return errors.Join(errs...)
225	}
226	
227	func discardSSHAdvertisement(stdout io.ReadCloser) (io.ReadCloser, error) {
228		buffered := bufio.NewReader(stdout)
229		header, err := buffered.Peek(4)
230		if err != nil {
231			if errors.Is(err, io.EOF) {
232				return &bufferedReadCloser{Reader: buffered, Closer: stdout}, nil
233			}
234			return nil, fmt.Errorf("peek SSH advertisement: %w", err)
235		}
236		if !looksLikePktlineHeader(header) {
237			return &bufferedReadCloser{Reader: buffered, Closer: stdout}, nil
238		}
239		reader := NewPacketReader(buffered)
240		for {
241			kind, _, err := reader.ReadPacket()
242			if err != nil {
243				return nil, err
244			}
245			if kind == PacketFlush {
246				break
247			}
248		}
249		return &bufferedReadCloser{Reader: reader.BufReader(), Closer: stdout}, nil
250	}
251	
252	func looksLikePktlineHeader(header []byte) bool {
253		if len(header) != 4 {
254			return false
255		}
256		var fixed [4]byte
257		copy(fixed[:], header)
258		switch string(fixed[:]) {
259		case "0000", "0001", "0002":
260			return true
261		}
262		_, err := parseHexLength(fixed)
263		return err == nil
264	}
265	
266	type sshRPCStream struct {
267		ctx     context.Context
268		stdout  io.ReadCloser
269		wait    func() error
270		copyErr <-chan error
271		stderr  *sshCommandError
272	
273		waitOnce sync.Once
274		waitErr  error
275	}
276	
277	type bufferedReadCloser struct {
278		*bufio.Reader
279		io.Closer
280	}
281	
282	func (s *sshRPCStream) Read(p []byte) (int, error) {
283		n, err := s.stdout.Read(p)
284		return n, err //nolint:wrapcheck // io.Reader contract requires forwarding EOF and stream errors as-is
285	}
286	
287	func (s *sshRPCStream) Close() error {
288		closeErr := s.stdout.Close()
289		s.waitOnce.Do(func() {
290			copyErr := <-s.copyErr
291			waitErr := s.wait()
292			if copyErr != nil {
293				s.waitErr = copyErr
294				if waitErr != nil {
295					s.waitErr = errors.Join(copyErr, s.stderr.wrap(waitErr))
296				}
297				return
298			}
299			if waitErr != nil {
300				s.waitErr = s.stderr.wrap(waitErr)
301			}
302			if s.ctx != nil && s.ctx.Err() != nil {
303				s.waitErr = errors.Join(s.ctx.Err(), s.waitErr)
304			}
305		})
306		return errors.Join(closeErr, s.waitErr)
307	}
308	
309	type sshCommandError struct {
310		mu  sync.Mutex
311		buf bytes.Buffer
312	}
313	
314	func (e *sshCommandError) Write(p []byte) (int, error) {
315		e.mu.Lock()
316		defer e.mu.Unlock()
317		return e.buf.Write(p) //nolint:wrapcheck // io.Writer implementation forwards buffer write errors verbatim
318	}
319	
320	func (e *sshCommandError) String() string {
321		e.mu.Lock()
322		defer e.mu.Unlock()
323		return strings.TrimSpace(e.buf.String())
324	}
325	
326	func (e *sshCommandError) wrap(err error) error {
327		if err == nil {
328			return nil
329		}
330		if msg := e.String(); msg != "" {
331			return fmt.Errorf("%w: %s", err, msg)
332		}
333		return err
334	}
